async function createFinalFormBuilderPage() {
  try {
    console.log('🔄 Creating final Form Builder page with custom sections...');

    const existingPage = await prisma.page.findFirst({
      where: {
        OR: [
          { slug: '/en/form-builder' },
          { title: 'Form Builder' }
        ]
      }
    });

    if (existingPage) {
      await prisma.page.update({
        where: { id: existingPage.id },
        data: {
          title: 'Form Builder',
          slug: '/en/form-builder',
          status: 'published',
          isBuilderPage: true,
          builderData: JSON.stringify({
            sections: finalFormBuilderSections
          }),
          updatedAt: new Date()
        }
      });
    } else {
      await prisma.page.create({
        data: {
          title: 'Form Builder',
          slug: '/en/form-builder',
          status: 'published',
          isBuilderPage: true,
          builderData: JSON.stringify({
            sections: finalFormBuilderSections
          }),
          createdAt: new Date(),
          updatedAt: new Date()
        }
      });
    }

    console.log('✅ Final Form Builder page created with custom sections!');
    
  } catch (error) {
    console.error('❌ Error:', error);
  } finally {
    await prisma.$disconnect();
  }
}

createFinalFormBuilderPage();